    #[test]
    fn test_update_alias_order_by_limit_without_where_uses_alias_in_internal_count_query() {
        let conn = Connection::open(":memory:").unwrap();
        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, v INTEGER);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (1, 10), (2, 20), (3, 30);")
            .unwrap();

        let affected = conn
            .execute("UPDATE t AS x SET v = v + 100 ORDER BY x.id ASC LIMIT 1;")
            .unwrap();

        let rows = conn.query("SELECT id, v FROM t ORDER BY id;").unwrap();
        assert_eq!(rows.len(), 3);
        assert_eq!(
            row_values(&rows[0]),
            vec![SqliteValue::Integer(1), SqliteValue::Integer(110)]
        );
        assert_eq!(
            row_values(&rows[1]),
            vec![SqliteValue::Integer(2), SqliteValue::Integer(20)]
        );
        assert_eq!(
            row_values(&rows[2]),
            vec![SqliteValue::Integer(3), SqliteValue::Integer(30)]
        );
        assert_eq!(affected, 1, "LIMIT 1 must update exactly one row");
    }

