    /// Probe test: edge cases in type coercion, NULL handling, and expressions.
    #[test]
    fn test_probe_type_coercion_and_edge_cases() {
        let conn = Connection::open(":memory:").unwrap();

        // typeof() for various types
        let rows = conn
            .query("SELECT typeof(1), typeof(1.5), typeof('hi'), typeof(NULL), typeof(X'AB');")
            .unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("integer".to_owned()));
        assert_eq!(rows[0].values()[1], SqliteValue::Text("real".to_owned()));
        assert_eq!(rows[0].values()[2], SqliteValue::Text("text".to_owned()));
        assert_eq!(rows[0].values()[3], SqliteValue::Text("null".to_owned()));
        assert_eq!(rows[0].values()[4], SqliteValue::Text("blob".to_owned()));

        // CAST conversions
        assert_eq!(
            conn.query("SELECT CAST('123' AS INTEGER);").unwrap()[0].values()[0],
            SqliteValue::Integer(123)
        );
        assert_eq!(
            conn.query("SELECT CAST(3.14 AS INTEGER);").unwrap()[0].values()[0],
            SqliteValue::Integer(3)
        );
        assert_eq!(
            conn.query("SELECT CAST(42 AS TEXT);").unwrap()[0].values()[0],
            SqliteValue::Text("42".to_owned())
        );

        // NULL propagation in arithmetic
        assert_eq!(
            conn.query("SELECT 1 + NULL;").unwrap()[0].values()[0],
            SqliteValue::Null
        );
        assert_eq!(
            conn.query("SELECT NULL || 'text';").unwrap()[0].values()[0],
            SqliteValue::Null
        );

        // Division edge cases
        assert_eq!(
            conn.query("SELECT 7 / 2;").unwrap()[0].values()[0],
            SqliteValue::Integer(3) // integer division
        );
        assert_eq!(
            conn.query("SELECT 7.0 / 2;").unwrap()[0].values()[0],
            SqliteValue::Float(3.5)
        );
        assert_eq!(
            conn.query("SELECT 7 % 3;").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );

        // String comparison (case-sensitive by default)
        assert_eq!(
            conn.query("SELECT 'ABC' = 'abc';").unwrap()[0].values()[0],
            SqliteValue::Integer(0)
        );
        assert_eq!(
            conn.query("SELECT 'ABC' = 'ABC';").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );

        // LIKE is case-insensitive for ASCII
        assert_eq!(
            conn.query("SELECT 'Hello' LIKE 'hello';").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );
        assert_eq!(
            conn.query("SELECT 'Hello' LIKE 'h%';").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );

        // GLOB is case-sensitive
        assert_eq!(
            conn.query("SELECT 'Hello' GLOB 'Hello';").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );
        assert_eq!(
            conn.query("SELECT 'Hello' GLOB 'hello';").unwrap()[0].values()[0],
            SqliteValue::Integer(0)
        );

        // Nested COALESCE / NULLIF
        assert_eq!(
            conn.query("SELECT COALESCE(NULL, NULL, 42);").unwrap()[0].values()[0],
            SqliteValue::Integer(42)
        );
        assert_eq!(
            conn.query("SELECT NULLIF(5, 5);").unwrap()[0].values()[0],
            SqliteValue::Null
        );
        assert_eq!(
            conn.query("SELECT NULLIF(5, 6);").unwrap()[0].values()[0],
            SqliteValue::Integer(5)
        );

        // Unary minus
        assert_eq!(
            conn.query("SELECT -42;").unwrap()[0].values()[0],
            SqliteValue::Integer(-42)
        );

        // Boolean-like: no native bool, uses 0/1
        assert_eq!(
            conn.query("SELECT 1 AND 1;").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );
        assert_eq!(
            conn.query("SELECT 1 AND 0;").unwrap()[0].values()[0],
            SqliteValue::Integer(0)
        );
        assert_eq!(
            conn.query("SELECT 0 OR 1;").unwrap()[0].values()[0],
            SqliteValue::Integer(1)
        );
        assert_eq!(
            conn.query("SELECT NOT 1;").unwrap()[0].values()[0],
            SqliteValue::Integer(0)
        );
    }

    /// Probe test: multi-table operations, self-joins, correlated updates.
    #[test]
    fn test_probe_multi_table_and_self_join() {
        let conn = Connection::open(":memory:").unwrap();

        conn.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT, parent_id INTEGER);")
            .unwrap();
        conn.execute("INSERT INTO items VALUES (1, 'root', NULL);")
            .unwrap();
        conn.execute("INSERT INTO items VALUES (2, 'child1', 1);")
            .unwrap();
        conn.execute("INSERT INTO items VALUES (3, 'child2', 1);")
            .unwrap();
        conn.execute("INSERT INTO items VALUES (4, 'grandchild', 2);")
            .unwrap();

        // Self-join: find parent names
        let rows = conn
            .query("SELECT c.name, p.name FROM items c INNER JOIN items p ON c.parent_id = p.id ORDER BY c.id;")
            .unwrap();
        assert_eq!(rows.len(), 3);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("child1".to_owned()));
        assert_eq!(rows[0].values()[1], SqliteValue::Text("root".to_owned()));
        assert_eq!(
            rows[2].values()[0],
            SqliteValue::Text("grandchild".to_owned())
        );
        assert_eq!(rows[2].values()[1], SqliteValue::Text("child1".to_owned()));

        // Multi-column INSERT from SELECT
        conn.execute(
            "CREATE TABLE items_copy (id INTEGER PRIMARY KEY, name TEXT, parent_id INTEGER);",
        )
        .unwrap();
        conn.execute("INSERT INTO items_copy SELECT * FROM items;")
            .unwrap();
        let rows = conn.query("SELECT COUNT(*) FROM items_copy;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(4));

        // DELETE with subquery
        conn.execute("DELETE FROM items_copy WHERE parent_id IS NOT NULL;")
            .unwrap();
        let rows = conn.query("SELECT COUNT(*) FROM items_copy;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(1));

        // UPDATE with expression
        conn.execute("UPDATE items SET name = name || '_updated' WHERE parent_id IS NULL;")
            .unwrap();
        let rows = conn.query("SELECT name FROM items WHERE id = 1;").unwrap();
        assert_eq!(
            rows[0].values()[0],
            SqliteValue::Text("root_updated".to_owned())
        );

        // REPLACE (INSERT OR REPLACE)
        conn.execute("INSERT OR REPLACE INTO items VALUES (1, 'new_root', NULL);")
            .unwrap();
        let rows = conn.query("SELECT name FROM items WHERE id = 1;").unwrap();
        assert_eq!(
            rows[0].values()[0],
            SqliteValue::Text("new_root".to_owned())
        );
    }

    /// Probe test: complex WHERE predicates and subqueries.
    #[test]
    fn test_probe_complex_where_and_subqueries() {
        let conn = Connection::open(":memory:").unwrap();

        conn.execute(
            "CREATE TABLE products (id INTEGER PRIMARY KEY, name TEXT, price REAL, category TEXT);",
        )
        .unwrap();
        conn.execute("INSERT INTO products VALUES (1, 'Widget', 9.99, 'A');")
            .unwrap();
        conn.execute("INSERT INTO products VALUES (2, 'Gadget', 19.99, 'B');")
            .unwrap();
        conn.execute("INSERT INTO products VALUES (3, 'Doohickey', 5.99, 'A');")
            .unwrap();
        conn.execute("INSERT INTO products VALUES (4, 'Thingamajig', 29.99, 'B');")
            .unwrap();
        conn.execute("INSERT INTO products VALUES (5, 'Whatchamacallit', 14.99, 'A');")
            .unwrap();

        // BETWEEN
        let rows = conn
            .query("SELECT name FROM products WHERE price BETWEEN 10.0 AND 25.0 ORDER BY name;")
            .unwrap();
        assert_eq!(rows.len(), 2);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("Gadget".to_owned()));
        assert_eq!(
            rows[1].values()[0],
            SqliteValue::Text("Whatchamacallit".to_owned())
        );

        // IN list
        let rows = conn
            .query("SELECT name FROM products WHERE id IN (1, 3, 5) ORDER BY id;")
            .unwrap();
        assert_eq!(rows.len(), 3);

        // Correlated subquery: products more expensive than category average
        let rows = conn
            .query(
                "SELECT name FROM products p WHERE price > (SELECT AVG(price) FROM products WHERE category = p.category) ORDER BY name;",
            )
            .unwrap();
        // Category A: avg = (9.99+5.99+14.99)/3 ≈ 10.32 → Whatchamacallit (14.99)
        // Category B: avg = (19.99+29.99)/2 = 24.99 → Thingamajig (29.99)
        assert_eq!(rows.len(), 2);
        assert_eq!(
            rows[0].values()[0],
            SqliteValue::Text("Thingamajig".to_owned())
        );
        assert_eq!(
            rows[1].values()[0],
            SqliteValue::Text("Whatchamacallit".to_owned())
        );

        // NOT IN subquery
        let rows = conn
            .query(
                "SELECT name FROM products WHERE category NOT IN (SELECT category FROM products WHERE price > 20.0) ORDER BY name;",
            )
            .unwrap();
        // Category B has a product > 20.0 (Thingamajig), so exclude B
        // Only category A products remain
        assert_eq!(rows.len(), 3);

        // COUNT DISTINCT
        let rows = conn
            .query("SELECT COUNT(DISTINCT category) FROM products;")
            .unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(2));

        // Nested function calls
        let rows = conn
            .query("SELECT UPPER(SUBSTR('hello world', 1, 5));")
            .unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("HELLO".to_owned()));

        // Multiple ORDER BY columns
        let rows = conn
            .query("SELECT * FROM products ORDER BY category ASC, price DESC;")
            .unwrap();
        // A: Whatchamacallit(14.99), Widget(9.99), Doohickey(5.99)
        // B: Thingamajig(29.99), Gadget(19.99)
        assert_eq!(rows.len(), 5);
        assert_eq!(
            rows[0].values()[1],
            SqliteValue::Text("Whatchamacallit".to_owned())
        );
        assert_eq!(
            rows[3].values()[1],
            SqliteValue::Text("Thingamajig".to_owned())
        );
    }

    /// Probe test: views, indexes, and schema operations.
    #[test]
    fn test_probe_views_indexes_schema() {
        let conn = Connection::open(":memory:").unwrap();

        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, name TEXT, score INTEGER);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (1, 'Alice', 90);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (2, 'Bob', 85);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (3, 'Charlie', 95);")
            .unwrap();

        // CREATE VIEW + query through it
        conn.execute("CREATE VIEW v_high_scores AS SELECT name, score FROM t WHERE score >= 90;")
            .unwrap();
        let rows = conn
            .query("SELECT * FROM v_high_scores ORDER BY name;")
            .unwrap();
        assert_eq!(rows.len(), 2);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("Alice".to_owned()));
        assert_eq!(rows[1].values()[0], SqliteValue::Text("Charlie".to_owned()));

        // CREATE INDEX + verify it's used (just make sure no error)
        conn.execute("CREATE INDEX idx_score ON t(score);").unwrap();
        let rows = conn.query("SELECT name FROM t WHERE score = 85;").unwrap();
        assert_eq!(rows.len(), 1);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("Bob".to_owned()));

        // UNIQUE INDEX + conflict
        conn.execute("CREATE UNIQUE INDEX idx_name ON t(name);")
            .unwrap();
        let err = conn
            .execute("INSERT INTO t VALUES (4, 'Alice', 80);")
            .unwrap_err();
        assert!(
            format!("{err}").contains("UNIQUE") || format!("{err}").contains("unique"),
            "Expected unique constraint error, got: {err}"
        );

        // DROP VIEW
        conn.execute("DROP VIEW v_high_scores;").unwrap();
        let err = conn.query("SELECT * FROM v_high_scores;").unwrap_err();
        assert!(
            format!("{err}").contains("v_high_scores"),
            "Expected missing view error, got: {err}"
        );

        // ALTER TABLE ADD COLUMN
        conn.execute("ALTER TABLE t ADD COLUMN grade TEXT DEFAULT 'N/A';")
            .unwrap();
        let rows = conn.query("SELECT grade FROM t WHERE id = 1;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("N/A".to_owned()));

        // PRAGMA table_info
        let rows = conn.query("PRAGMA table_info(t);").unwrap();
        assert!(rows.len() >= 4); // id, name, score, grade
    }

    /// Probe test: transaction semantics, savepoints, and isolation.
    #[test]
    fn test_probe_transaction_semantics() {
        let conn = Connection::open(":memory:").unwrap();

        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT);")
            .unwrap();
        conn.execute("INSERT INTO t VALUES (1, 'original');")
            .unwrap();

        // Basic transaction commit
        conn.execute("BEGIN;").unwrap();
        conn.execute("UPDATE t SET val = 'updated' WHERE id = 1;")
            .unwrap();
        conn.execute("COMMIT;").unwrap();
        let rows = conn.query("SELECT val FROM t WHERE id = 1;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("updated".to_owned()));

        // Transaction rollback
        conn.execute("BEGIN;").unwrap();
        conn.execute("UPDATE t SET val = 'rolled_back' WHERE id = 1;")
            .unwrap();
        conn.execute("ROLLBACK;").unwrap();
        let rows = conn.query("SELECT val FROM t WHERE id = 1;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Text("updated".to_owned()));

        // Savepoint + release
        conn.execute("BEGIN;").unwrap();
        conn.execute("SAVEPOINT sp1;").unwrap();
        conn.execute("INSERT INTO t VALUES (2, 'in_savepoint');")
            .unwrap();
        conn.execute("RELEASE sp1;").unwrap();
        conn.execute("COMMIT;").unwrap();
        let rows = conn.query("SELECT COUNT(*) FROM t;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(2));

        // Savepoint + rollback to savepoint
        conn.execute("BEGIN;").unwrap();
        conn.execute("SAVEPOINT sp2;").unwrap();
        conn.execute("INSERT INTO t VALUES (3, 'will_rollback');")
            .unwrap();
        conn.execute("ROLLBACK TO sp2;").unwrap();
        conn.execute("COMMIT;").unwrap();
        let rows = conn.query("SELECT COUNT(*) FROM t;").unwrap();
        assert_eq!(rows[0].values()[0], SqliteValue::Integer(2));

        // ROLLBACK outside transaction is an error
        let err = conn.execute("ROLLBACK;").unwrap_err();
        assert!(format!("{err}").contains("no transaction"));

        // Double BEGIN is an error
        conn.execute("BEGIN;").unwrap();
        let err = conn.execute("BEGIN;").unwrap_err();
        assert!(
            format!("{err}").contains("transaction") || format!("{err}").contains("within"),
            "Expected error about nested transaction, got: {err}"
        );
        conn.execute("ROLLBACK;").unwrap();
    }

    /// Probe test: three-table JOIN, CROSS JOIN, aggregates with multiple
    /// GROUP BY columns.
    #[test]
    fn test_probe_multi_join_and_groupby() {
        let conn = Connection::open(":memory:").unwrap();

        conn.execute("CREATE TABLE regions (id INTEGER PRIMARY KEY, name TEXT);")
            .unwrap();
        conn.execute("INSERT INTO regions VALUES (1, 'North');")
            .unwrap();
        conn.execute("INSERT INTO regions VALUES (2, 'South');")
            .unwrap();

        conn.execute("CREATE TABLE stores (id INTEGER PRIMARY KEY, name TEXT, region_id INTEGER);")
            .unwrap();
        conn.execute("INSERT INTO stores VALUES (1, 'StoreA', 1);")
            .unwrap();
        conn.execute("INSERT INTO stores VALUES (2, 'StoreB', 1);")
            .unwrap();
        conn.execute("INSERT INTO stores VALUES (3, 'StoreC', 2);")
            .unwrap();

        conn.execute(
            "CREATE TABLE sales (id INTEGER PRIMARY KEY, store_id INTEGER, amount INTEGER);",
        )
        .unwrap();
        conn.execute("INSERT INTO sales VALUES (1, 1, 100);")
            .unwrap();
        conn.execute("INSERT INTO sales VALUES (2, 1, 200);")
            .unwrap();
        conn.execute("INSERT INTO sales VALUES (3, 2, 150);")
            .unwrap();
        conn.execute("INSERT INTO sales VALUES (4, 3, 300);")
            .unwrap();

        // Two-table JOIN with aggregate + GROUP BY
        let rows = conn
            .query("SELECT s.name, SUM(sa.amount) FROM stores s JOIN sales sa ON s.id = sa.store_id GROUP BY s.name ORDER BY s.name;")
            .unwrap();
        assert_eq!(rows.len(), 3);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("StoreA".to_owned()));
        assert_eq!(rows[0].values()[1], SqliteValue::Integer(300));
        assert_eq!(rows[2].values()[1], SqliteValue::Integer(300));

        // Three-table JOIN
        let rows = conn
            .query("SELECT r.name, s.name, sa.amount FROM regions r JOIN stores s ON r.id = s.region_id JOIN sales sa ON s.id = sa.store_id ORDER BY sa.amount;")
            .unwrap();
        assert_eq!(rows.len(), 4);
        assert_eq!(rows[0].values()[2], SqliteValue::Integer(100));
        assert_eq!(rows[3].values()[2], SqliteValue::Integer(300));

        // Aggregate with multiple GROUP BY columns
        let rows = conn
            .query("SELECT r.name, COUNT(*) FROM regions r JOIN stores s ON r.id = s.region_id JOIN sales sa ON s.id = sa.store_id GROUP BY r.name ORDER BY r.name;")
            .unwrap();
        assert_eq!(rows.len(), 2);
        assert_eq!(rows[0].values()[0], SqliteValue::Text("North".to_owned()));
        assert_eq!(rows[0].values()[1], SqliteValue::Integer(3)); // 3 sales in North
        assert_eq!(rows[1].values()[0], SqliteValue::Text("South".to_owned()));
        assert_eq!(rows[1].values()[1], SqliteValue::Integer(1)); // 1 sale in South
    }

