    /// Conformance oracle: text-to-number coercion edge cases in arithmetic
    #[test]
    fn test_conformance_text_number_coercion_arith() {
        let fconn = Connection::open(":memory:").unwrap();
        let rconn = rusqlite::Connection::open_in_memory().unwrap();

        let queries = [
            // Non-numeric text → integer 0
            "SELECT typeof('abc' + 0)",
            "SELECT 'abc' + 0",
            "SELECT 'abc' * 1",
            "SELECT typeof('abc' * 1)",
            // Numeric prefix text → integer
            "SELECT '42abc' + 0",
            "SELECT typeof('42abc' + 0)",
            // Float prefix text → float
            "SELECT '3.14abc' + 0",
            "SELECT typeof('3.14abc' + 0)",
            // Pure integer text → integer
            "SELECT '100' + 0",
            "SELECT typeof('100' + 0)",
            // Pure float text → float
            "SELECT '1.5' + 0",
            "SELECT typeof('1.5' + 0)",
            // Scientific notation
            "SELECT '1e2' + 0",
            "SELECT typeof('1e2' + 0)",
            // Empty string → integer 0
            "SELECT '' + 0",
            "SELECT typeof('' + 0)",
            // Leading whitespace
            "SELECT '  42' + 0",
            "SELECT typeof('  42' + 0)",
            // Division with text
            "SELECT '10' / 3",
            "SELECT typeof('10' / 3)",
            "SELECT '10.0' / 3",
            "SELECT typeof('10.0' / 3)",
        ];

        let mismatches = oracle_compare(&fconn, &rconn, &queries);
        if !mismatches.is_empty() {
            for m in &mismatches {
                eprintln!("{m}\n");
            }
            panic!("{} text-number coercion mismatches", mismatches.len());
        }
    }

